void PEGTransformerFactory::InitializeAlterStatement(PEGTransformer &transformer, TransformStack &stack,
                                                     TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	child_result_count++;
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	child_slot--;
	stack.PushFrame(list_pr.GetChild(1), ALTER_OPTIONS_OPS, parent_frame_index, child_slot);
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeAlterStatement(PEGTransformer &transformer,
                                                                               TransformStackFrame &frame) {
	idx_t child_slot = 0;
	auto alter_options = frame.TakeResult<unique_ptr<AlterInfo>>(child_slot);
	child_slot++;
	auto result = TransformAlterStatement(transformer, std::move(alter_options));
	return make_uniq<TypedTransformResult<unique_ptr<SQLStatement>>>(std::move(result));
}

void PEGTransformerFactory::InitializeAlterOptions(PEGTransformer &transformer, TransformStack &stack,
                                                   TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	auto &choice_pr = list_pr.Child<ChoiceParseResult>(0);
	auto &choice_result = choice_pr.GetResult();
	auto &trampoline_ops = GeneratedTrampolineOps();
	auto entry = trampoline_ops.find(choice_result.name);
	if (entry == trampoline_ops.end()) {
		frame.child_results.resize(0);
		return;
	}
	frame.child_results.resize(1);
	stack.PushFrame(choice_result, *entry->second, frame, 0);
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeAlterOptions(PEGTransformer &transformer,
                                                                             TransformStackFrame &frame) {
	auto result = frame.TakeResult<unique_ptr<AlterInfo>>(0);
	return make_uniq<TypedTransformResult<unique_ptr<AlterInfo>>>(std::move(result));
}

void PEGTransformerFactory::InitializeAlterTableStmt(PEGTransformer &transformer, TransformStack &stack,
                                                     TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	auto &if_exists_opt_0 = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (if_exists_opt_0.HasResult()) {
		child_result_count++;
	}
	child_result_count++;
	auto alter_table_options_children_2 = ExtractParseResultsFromList(list_pr.GetChild(3));
	child_result_count += alter_table_options_children_2.size();
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	child_slot -= alter_table_options_children_2.size();
	for (idx_t child_idx = alter_table_options_children_2.size(); child_idx > 0; child_idx--) {
		auto result_idx = child_idx - 1;
		stack.PushFrame(alter_table_options_children_2[result_idx].get(), ALTER_TABLE_OPTIONS_OPS, parent_frame_index,
		                child_slot + result_idx);
	}
	child_slot--;
	stack.PushFrame(list_pr.GetChild(2), BASE_TABLE_NAME_OPS, parent_frame_index, child_slot);
	if (if_exists_opt_0.HasResult()) {
		child_slot--;
		stack.PushFrame(if_exists_opt_0.GetResult(), IF_EXISTS_OPS, parent_frame_index, child_slot);
	}
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeAlterTableStmt(PEGTransformer &transformer,
                                                                               TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	optional<bool> if_exists {};
	auto &if_exists_opt = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (if_exists_opt.HasResult()) {
		auto if_exists_value = frame.TakeResult<bool>(child_slot);
		if_exists = if_exists_value;
		child_slot++;
	}
	auto base_table_name = frame.TakeResult<unique_ptr<BaseTableRef>>(child_slot);
	child_slot++;
	vector<unique_ptr<AlterTableInfo>> alter_table_options;
	auto alter_table_options_items = ExtractParseResultsFromList(list_pr.GetChild(3));
	for (idx_t child_idx = 0; child_idx < alter_table_options_items.size(); child_idx++) {
		auto &alter_table_options_item = alter_table_options_items[child_idx];
		auto alter_table_options_child_value = frame.TakeResult<unique_ptr<AlterTableInfo>>(child_slot + child_idx);
		alter_table_options.push_back(std::move(alter_table_options_child_value));
	}
	child_slot += alter_table_options_items.size();
	auto result =
	    TransformAlterTableStmt(transformer, if_exists, std::move(base_table_name), std::move(alter_table_options));
	return make_uniq<TypedTransformResult<unique_ptr<AlterInfo>>>(std::move(result));
}

void PEGTransformerFactory::InitializeAlterSchemaStmt(PEGTransformer &transformer, TransformStack &stack,
                                                      TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	auto &if_exists_opt_0 = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (if_exists_opt_0.HasResult()) {
		child_result_count++;
	}
	child_result_count++;
	child_result_count++;
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	child_slot--;
	stack.PushFrame(list_pr.GetChild(3), RENAME_ALTER_OPS, parent_frame_index, child_slot);
	child_slot--;
	stack.PushFrame(list_pr.GetChild(2), QUALIFIED_NAME_OPS, parent_frame_index, child_slot);
	if (if_exists_opt_0.HasResult()) {
		child_slot--;
		stack.PushFrame(if_exists_opt_0.GetResult(), IF_EXISTS_OPS, parent_frame_index, child_slot);
	}
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeAlterSchemaStmt(PEGTransformer &transformer,
                                                                                TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	optional<bool> if_exists {};
	auto &if_exists_opt = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (if_exists_opt.HasResult()) {
		auto if_exists_value = frame.TakeResult<bool>(child_slot);
		if_exists = if_exists_value;
		child_slot++;
	}
	auto qualified_name = frame.TakeResult<QualifiedName>(child_slot);
	child_slot++;
	auto rename_alter = frame.TakeResult<unique_ptr<AlterTableInfo>>(child_slot);
	child_slot++;
	auto result = TransformAlterSchemaStmt(transformer, if_exists, qualified_name, std::move(rename_alter));
	return make_uniq<TypedTransformResult<unique_ptr<AlterInfo>>>(std::move(result));
}

