void PEGTransformerFactory::InitializeAddColumnEntry(PEGTransformer &transformer, TransformStack &stack,
                                                     TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	child_result_count++;
	auto &type_opt_1 = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (type_opt_1.HasResult()) {
		child_result_count++;
	}
	auto &generated_column_opt_2 = list_pr.GetChild(2).Cast<OptionalParseResult>();
	if (generated_column_opt_2.HasResult()) {
		child_result_count++;
	}
	auto &column_constraint_opt_3 = list_pr.GetChild(3).Cast<OptionalParseResult>();
	if (column_constraint_opt_3.HasResult()) {
		auto &column_constraint_repeat_3 = column_constraint_opt_3.GetResult().Cast<RepeatParseResult>();
		child_result_count += column_constraint_repeat_3.GetChildren().size();
	}
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	if (column_constraint_opt_3.HasResult()) {
		auto &column_constraint_repeat_3 = column_constraint_opt_3.GetResult().Cast<RepeatParseResult>();
		auto column_constraint_children_3 = column_constraint_repeat_3.GetChildren();
		child_slot -= column_constraint_children_3.size();
		for (idx_t child_idx = column_constraint_children_3.size(); child_idx > 0; child_idx--) {
			auto result_idx = child_idx - 1;
			stack.PushFrame(column_constraint_children_3[result_idx].get(), COLUMN_CONSTRAINT_OPS, parent_frame_index,
			                child_slot + result_idx);
		}
	}
	if (generated_column_opt_2.HasResult()) {
		child_slot--;
		stack.PushFrame(generated_column_opt_2.GetResult(), GENERATED_COLUMN_OPS, parent_frame_index, child_slot);
	}
	if (type_opt_1.HasResult()) {
		child_slot--;
		stack.PushFrame(type_opt_1.GetResult(), TYPE_OPS, parent_frame_index, child_slot);
	}
	child_slot--;
	stack.PushFrame(list_pr.GetChild(0), DOTTED_IDENTIFIER_OPS, parent_frame_index, child_slot);
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeAddColumnEntry(PEGTransformer &transformer,
                                                                               TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	auto dotted_identifier = frame.TakeResult<vector<string>>(child_slot);
	child_slot++;
	optional<LogicalType> type {};
	auto &type_opt = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (type_opt.HasResult()) {
		auto type_value = frame.TakeResult<LogicalType>(child_slot);
		type = type_value;
		child_slot++;
	}
	optional<GeneratedColumnDefinition> generated_column {};
	auto &generated_column_opt = list_pr.GetChild(2).Cast<OptionalParseResult>();
	if (generated_column_opt.HasResult()) {
		auto generated_column_value = frame.TakeResult<GeneratedColumnDefinition>(child_slot);
		generated_column = std::move(generated_column_value);
		child_slot++;
	}
	optional<vector<ColumnConstraintEntry>> column_constraint {};
	auto &column_constraint_opt = list_pr.GetChild(3).Cast<OptionalParseResult>();
	if (column_constraint_opt.HasResult()) {
		vector<ColumnConstraintEntry> column_constraint_value;
		auto &column_constraint_repeat = column_constraint_opt.GetResult().Cast<RepeatParseResult>();
		auto column_constraint_children = column_constraint_repeat.GetChildren();
		for (idx_t child_idx = 0; child_idx < column_constraint_children.size(); child_idx++) {
			column_constraint_value.push_back(frame.TakeResult<ColumnConstraintEntry>(child_slot + child_idx));
		}
		column_constraint = std::move(column_constraint_value);
		child_slot += column_constraint_children.size();
	}
	auto result = TransformAddColumnEntry(transformer, dotted_identifier, type, std::move(generated_column),
	                                      std::move(column_constraint));
	return make_uniq<TypedTransformResult<AddColumnEntry>>(std::move(result));
}

