void PEGTransformerFactory::InitializeExpressionStatement(PEGTransformer &transformer, TransformStack &stack,
                                                          TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	auto expression_alias_children_0 = ExtractParseResultsFromList(list_pr.GetChild(0));
	child_result_count += expression_alias_children_0.size();
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	child_slot -= expression_alias_children_0.size();
	for (idx_t child_idx = expression_alias_children_0.size(); child_idx > 0; child_idx--) {
		auto result_idx = child_idx - 1;
		stack.PushFrame(expression_alias_children_0[result_idx].get(), EXPRESSION_ALIAS_OPS, parent_frame_index,
		                child_slot + result_idx);
	}
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeExpressionStatement(PEGTransformer &transformer,
                                                                                    TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	vector<unique_ptr<ParsedExpression>> expression_alias;
	auto expression_alias_items = ExtractParseResultsFromList(list_pr.GetChild(0));
	for (idx_t child_idx = 0; child_idx < expression_alias_items.size(); child_idx++) {
		auto &expression_alias_item = expression_alias_items[child_idx];
		auto expression_alias_child_value = frame.TakeResult<unique_ptr<ParsedExpression>>(child_slot + child_idx);
		expression_alias.push_back(std::move(expression_alias_child_value));
	}
	child_slot += expression_alias_items.size();
	auto result = TransformExpressionStatement(transformer, std::move(expression_alias));
	return make_uniq<TypedTransformResult<unique_ptr<SQLStatement>>>(std::move(result));
}

