void PEGTransformerFactory::InitializeType(PEGTransformer &transformer, TransformStack &stack,
                                           TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	child_result_count++;
	auto &array_bounds_opt_1 = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (array_bounds_opt_1.HasResult()) {
		auto &array_bounds_repeat_1 = array_bounds_opt_1.GetResult().Cast<RepeatParseResult>();
		child_result_count += array_bounds_repeat_1.GetChildren().size();
	}
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	if (array_bounds_opt_1.HasResult()) {
		auto &array_bounds_repeat_1 = array_bounds_opt_1.GetResult().Cast<RepeatParseResult>();
		auto array_bounds_children_1 = array_bounds_repeat_1.GetChildren();
		child_slot -= array_bounds_children_1.size();
		for (idx_t child_idx = array_bounds_children_1.size(); child_idx > 0; child_idx--) {
			auto result_idx = child_idx - 1;
			stack.PushFrame(array_bounds_children_1[result_idx].get(), ARRAY_BOUNDS_OPS, parent_frame_index,
			                child_slot + result_idx);
		}
	}
	child_slot--;
	stack.PushFrame(list_pr.GetChild(0), TYPE_VARIATIONS_OPS, parent_frame_index, child_slot);
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeType(PEGTransformer &transformer,
                                                                     TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	auto type_variations = frame.TakeResult<unique_ptr<ParsedExpression>>(child_slot);
	child_slot++;
	optional<vector<int64_t>> array_bounds {};
	auto &array_bounds_opt = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (array_bounds_opt.HasResult()) {
		vector<int64_t> array_bounds_value;
		auto &array_bounds_repeat = array_bounds_opt.GetResult().Cast<RepeatParseResult>();
		auto array_bounds_children = array_bounds_repeat.GetChildren();
		for (idx_t child_idx = 0; child_idx < array_bounds_children.size(); child_idx++) {
			array_bounds_value.push_back(frame.TakeResult<int64_t>(child_slot + child_idx));
		}
		array_bounds = array_bounds_value;
		child_slot += array_bounds_children.size();
	}
	auto result = TransformType(transformer, std::move(type_variations), array_bounds);
	return make_uniq<TypedTransformResult<LogicalType>>(result);
}

