void PEGTransformerFactory::InitializeBitType(PEGTransformer &transformer, TransformStack &stack,
                                              TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	auto &expression_opt_0 = list_pr.GetChild(2).Cast<OptionalParseResult>();
	if (expression_opt_0.HasResult()) {
		auto expression_children_0 = ExtractParseResultsFromList(ExtractResultFromParens(expression_opt_0.GetResult()));
		child_result_count += expression_children_0.size();
	}
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	if (expression_opt_0.HasResult()) {
		auto expression_children_0 = ExtractParseResultsFromList(ExtractResultFromParens(expression_opt_0.GetResult()));
		child_slot -= expression_children_0.size();
		for (idx_t child_idx = expression_children_0.size(); child_idx > 0; child_idx--) {
			auto result_idx = child_idx - 1;
			stack.PushFrame(expression_children_0[result_idx].get(), EXPRESSION_OPS, parent_frame_index,
			                child_slot + result_idx);
		}
	}
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeBitType(PEGTransformer &transformer,
                                                                        TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	bool has_result {};
	auto &has_result_opt = list_pr.GetChild(1).Cast<OptionalParseResult>();
	has_result = has_result_opt.HasResult();
	optional<vector<unique_ptr<ParsedExpression>>> expression {};
	auto &expression_opt = list_pr.GetChild(2).Cast<OptionalParseResult>();
	if (expression_opt.HasResult()) {
		vector<unique_ptr<ParsedExpression>> expression_value;
		auto expression_items = ExtractParseResultsFromList(ExtractResultFromParens(expression_opt.GetResult()));
		for (idx_t child_idx = 0; child_idx < expression_items.size(); child_idx++) {
			auto &expression_item = expression_items[child_idx];
			auto expression_child_value = frame.TakeResult<unique_ptr<ParsedExpression>>(child_slot + child_idx);
			expression_value.push_back(std::move(expression_child_value));
		}
		expression = std::move(expression_value);
		child_slot += expression_items.size();
	}
	auto result = TransformBitType(transformer, has_result, std::move(expression));
	return make_uniq<TypedTransformResult<unique_ptr<ParsedExpression>>>(std::move(result));
}

