void PEGTransformerFactory::InitializeCopyTable(PEGTransformer &transformer, TransformStack &stack,
                                                TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	child_result_count++;
	auto &insert_column_list_opt_1 = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (insert_column_list_opt_1.HasResult()) {
		child_result_count++;
	}
	child_result_count++;
	child_result_count++;
	auto &copy_options_opt_4 = list_pr.GetChild(4).Cast<OptionalParseResult>();
	if (copy_options_opt_4.HasResult()) {
		child_result_count++;
	}
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	if (copy_options_opt_4.HasResult()) {
		child_slot--;
		stack.PushFrame(copy_options_opt_4.GetResult(), COPY_OPTIONS_OPS, parent_frame_index, child_slot);
	}
	child_slot--;
	stack.PushFrame(list_pr.GetChild(3), COPY_FILE_NAME_OPS, parent_frame_index, child_slot);
	child_slot--;
	stack.PushFrame(list_pr.GetChild(2), FROM_OR_TO_OPS, parent_frame_index, child_slot);
	if (insert_column_list_opt_1.HasResult()) {
		child_slot--;
		stack.PushFrame(insert_column_list_opt_1.GetResult(), INSERT_COLUMN_LIST_OPS, parent_frame_index, child_slot);
	}
	child_slot--;
	stack.PushFrame(list_pr.GetChild(0), BASE_TABLE_NAME_OPS, parent_frame_index, child_slot);
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeCopyTable(PEGTransformer &transformer,
                                                                          TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	auto base_table_name = frame.TakeResult<unique_ptr<BaseTableRef>>(child_slot);
	child_slot++;
	optional<vector<string>> insert_column_list {};
	auto &insert_column_list_opt = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (insert_column_list_opt.HasResult()) {
		auto insert_column_list_value = frame.TakeResult<vector<string>>(child_slot);
		insert_column_list = insert_column_list_value;
		child_slot++;
	}
	auto from_or_to = frame.TakeResult<bool>(child_slot);
	child_slot++;
	auto copy_file_name = frame.TakeResult<unique_ptr<ParsedExpression>>(child_slot);
	child_slot++;
	optional<vector<GenericCopyOption>> copy_options {};
	auto &copy_options_opt = list_pr.GetChild(4).Cast<OptionalParseResult>();
	if (copy_options_opt.HasResult()) {
		auto copy_options_value = frame.TakeResult<vector<GenericCopyOption>>(child_slot);
		copy_options = copy_options_value;
		child_slot++;
	}
	auto result = TransformCopyTable(transformer, std::move(base_table_name), insert_column_list, from_or_to,
	                                 std::move(copy_file_name), copy_options);
	return make_uniq<TypedTransformResult<unique_ptr<SQLStatement>>>(std::move(result));
}

