void PEGTransformerFactory::InitializeGenericCopyOptionList(PEGTransformer &transformer, TransformStack &stack,
                                                            TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	auto generic_copy_option_children_0 = ExtractParseResultsFromList(ExtractResultFromParens(list_pr.GetChild(0)));
	child_result_count += generic_copy_option_children_0.size();
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	child_slot -= generic_copy_option_children_0.size();
	for (idx_t child_idx = generic_copy_option_children_0.size(); child_idx > 0; child_idx--) {
		auto result_idx = child_idx - 1;
		stack.PushFrame(generic_copy_option_children_0[result_idx].get(), GENERIC_COPY_OPTION_OPS, parent_frame_index,
		                child_slot + result_idx);
	}
}

