void PEGTransformerFactory::InitializeCreateIndexStmt(PEGTransformer &transformer, TransformStack &stack,
                                                      TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	auto &unique_index_opt_0 = list_pr.GetChild(0).Cast<OptionalParseResult>();
	if (unique_index_opt_0.HasResult()) {
		child_result_count++;
	}
	auto &if_not_exists_opt_1 = list_pr.GetChild(2).Cast<OptionalParseResult>();
	if (if_not_exists_opt_1.HasResult()) {
		child_result_count++;
	}
	child_result_count++;
	auto &insert_column_list_opt_3 = list_pr.GetChild(6).Cast<OptionalParseResult>();
	if (insert_column_list_opt_3.HasResult()) {
		child_result_count++;
	}
	auto &index_type_opt_4 = list_pr.GetChild(7).Cast<OptionalParseResult>();
	if (index_type_opt_4.HasResult()) {
		child_result_count++;
	}
	auto &index_element_opt_5 = list_pr.GetChild(8).Cast<OptionalParseResult>();
	if (index_element_opt_5.HasResult()) {
		auto index_element_children_5 =
		    ExtractParseResultsFromList(ExtractResultFromParens(index_element_opt_5.GetResult()));
		child_result_count += index_element_children_5.size();
	}
	auto &with_list_opt_6 = list_pr.GetChild(9).Cast<OptionalParseResult>();
	if (with_list_opt_6.HasResult()) {
		child_result_count++;
	}
	auto &where_clause_opt_7 = list_pr.GetChild(10).Cast<OptionalParseResult>();
	if (where_clause_opt_7.HasResult()) {
		child_result_count++;
	}
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	if (where_clause_opt_7.HasResult()) {
		child_slot--;
		stack.PushFrame(where_clause_opt_7.GetResult(), WHERE_CLAUSE_OPS, parent_frame_index, child_slot);
	}
	if (with_list_opt_6.HasResult()) {
		child_slot--;
		stack.PushFrame(with_list_opt_6.GetResult(), WITH_LIST_OPS, parent_frame_index, child_slot);
	}
	if (index_element_opt_5.HasResult()) {
		auto index_element_children_5 =
		    ExtractParseResultsFromList(ExtractResultFromParens(index_element_opt_5.GetResult()));
		child_slot -= index_element_children_5.size();
		for (idx_t child_idx = index_element_children_5.size(); child_idx > 0; child_idx--) {
			auto result_idx = child_idx - 1;
			stack.PushFrame(index_element_children_5[result_idx].get(), INDEX_ELEMENT_OPS, parent_frame_index,
			                child_slot + result_idx);
		}
	}
	if (index_type_opt_4.HasResult()) {
		child_slot--;
		stack.PushFrame(index_type_opt_4.GetResult(), INDEX_TYPE_OPS, parent_frame_index, child_slot);
	}
	if (insert_column_list_opt_3.HasResult()) {
		child_slot--;
		stack.PushFrame(insert_column_list_opt_3.GetResult(), INSERT_COLUMN_LIST_OPS, parent_frame_index, child_slot);
	}
	child_slot--;
	stack.PushFrame(list_pr.GetChild(5), BASE_TABLE_NAME_OPS, parent_frame_index, child_slot);
	if (if_not_exists_opt_1.HasResult()) {
		child_slot--;
		stack.PushFrame(if_not_exists_opt_1.GetResult(), IF_NOT_EXISTS_OPS, parent_frame_index, child_slot);
	}
	if (unique_index_opt_0.HasResult()) {
		child_slot--;
		stack.PushFrame(unique_index_opt_0.GetResult(), UNIQUE_INDEX_OPS, parent_frame_index, child_slot);
	}
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeCreateIndexStmt(PEGTransformer &transformer,
                                                                                TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	optional<bool> unique_index {};
	auto &unique_index_opt = list_pr.GetChild(0).Cast<OptionalParseResult>();
	if (unique_index_opt.HasResult()) {
		auto unique_index_value = frame.TakeResult<bool>(child_slot);
		unique_index = unique_index_value;
		child_slot++;
	}
	optional<bool> if_not_exists {};
	auto &if_not_exists_opt = list_pr.GetChild(2).Cast<OptionalParseResult>();
	if (if_not_exists_opt.HasResult()) {
		auto if_not_exists_value = frame.TakeResult<bool>(child_slot);
		if_not_exists = if_not_exists_value;
		child_slot++;
	}
	optional<Identifier> index_name {};
	auto &index_name_opt = list_pr.GetChild(3).Cast<OptionalParseResult>();
	if (index_name_opt.HasResult()) {
		auto index_name_value = index_name_opt.GetResult().Cast<IdentifierParseResult>().identifier;
		index_name = index_name_value;
	}
	auto base_table_name = frame.TakeResult<unique_ptr<BaseTableRef>>(child_slot);
	child_slot++;
	optional<vector<string>> insert_column_list {};
	auto &insert_column_list_opt = list_pr.GetChild(6).Cast<OptionalParseResult>();
	if (insert_column_list_opt.HasResult()) {
		auto insert_column_list_value = frame.TakeResult<vector<string>>(child_slot);
		insert_column_list = insert_column_list_value;
		child_slot++;
	}
	optional<Identifier> index_type {};
	auto &index_type_opt = list_pr.GetChild(7).Cast<OptionalParseResult>();
	if (index_type_opt.HasResult()) {
		auto index_type_value = frame.TakeResult<Identifier>(child_slot);
		index_type = index_type_value;
		child_slot++;
	}
	optional<vector<unique_ptr<ParsedExpression>>> index_element {};
	auto &index_element_opt = list_pr.GetChild(8).Cast<OptionalParseResult>();
	if (index_element_opt.HasResult()) {
		vector<unique_ptr<ParsedExpression>> index_element_value;
		auto index_element_items = ExtractParseResultsFromList(ExtractResultFromParens(index_element_opt.GetResult()));
		for (idx_t child_idx = 0; child_idx < index_element_items.size(); child_idx++) {
			auto &index_element_item = index_element_items[child_idx];
			auto index_element_child_value = frame.TakeResult<unique_ptr<ParsedExpression>>(child_slot + child_idx);
			index_element_value.push_back(std::move(index_element_child_value));
		}
		index_element = std::move(index_element_value);
		child_slot += index_element_items.size();
	}
	optional<case_insensitive_map_t<unique_ptr<ParsedExpression>>> with_list {};
	auto &with_list_opt = list_pr.GetChild(9).Cast<OptionalParseResult>();
	if (with_list_opt.HasResult()) {
		auto with_list_value = frame.TakeResult<case_insensitive_map_t<unique_ptr<ParsedExpression>>>(child_slot);
		with_list = std::move(with_list_value);
		child_slot++;
	}
	optional<unique_ptr<ParsedExpression>> where_clause {};
	auto &where_clause_opt = list_pr.GetChild(10).Cast<OptionalParseResult>();
	if (where_clause_opt.HasResult()) {
		auto where_clause_value = frame.TakeResult<unique_ptr<ParsedExpression>>(child_slot);
		where_clause = std::move(where_clause_value);
		child_slot++;
	}
	auto result = TransformCreateIndexStmt(transformer, unique_index, if_not_exists, index_name,
	                                       std::move(base_table_name), insert_column_list, index_type,
	                                       std::move(index_element), std::move(with_list), std::move(where_clause));
	return make_uniq<TypedTransformResult<unique_ptr<CreateStatement>>>(std::move(result));
}

