void PEGTransformerFactory::InitializeIndexElement(PEGTransformer &transformer, TransformStack &stack,
                                                   TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	child_result_count++;
	auto &desc_or_asc_opt_1 = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (desc_or_asc_opt_1.HasResult()) {
		child_result_count++;
	}
	auto &nulls_first_or_last_opt_2 = list_pr.GetChild(2).Cast<OptionalParseResult>();
	if (nulls_first_or_last_opt_2.HasResult()) {
		child_result_count++;
	}
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	if (nulls_first_or_last_opt_2.HasResult()) {
		child_slot--;
		stack.PushFrame(nulls_first_or_last_opt_2.GetResult(), NULLS_FIRST_OR_LAST_OPS, parent_frame_index, child_slot);
	}
	if (desc_or_asc_opt_1.HasResult()) {
		child_slot--;
		stack.PushFrame(desc_or_asc_opt_1.GetResult(), DESC_OR_ASC_OPS, parent_frame_index, child_slot);
	}
	child_slot--;
	stack.PushFrame(list_pr.GetChild(0), EXPRESSION_OPS, parent_frame_index, child_slot);
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeIndexElement(PEGTransformer &transformer,
                                                                             TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	auto expression = frame.TakeResult<unique_ptr<ParsedExpression>>(child_slot);
	child_slot++;
	optional<OrderType> desc_or_asc {};
	auto &desc_or_asc_opt = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (desc_or_asc_opt.HasResult()) {
		auto desc_or_asc_value = frame.TakeResult<OrderType>(child_slot);
		desc_or_asc = desc_or_asc_value;
		child_slot++;
	}
	optional<OrderByNullType> nulls_first_or_last {};
	auto &nulls_first_or_last_opt = list_pr.GetChild(2).Cast<OptionalParseResult>();
	if (nulls_first_or_last_opt.HasResult()) {
		auto nulls_first_or_last_value = frame.TakeResult<OrderByNullType>(child_slot);
		nulls_first_or_last = nulls_first_or_last_value;
		child_slot++;
	}
	auto result = TransformIndexElement(transformer, std::move(expression), desc_or_asc, nulls_first_or_last);
	return make_uniq<TypedTransformResult<unique_ptr<ParsedExpression>>>(std::move(result));
}

