void PEGTransformerFactory::InitializeCreateMacroStmt(PEGTransformer &transformer, TransformStack &stack,
                                                      TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	child_result_count++;
	auto &if_not_exists_opt_1 = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (if_not_exists_opt_1.HasResult()) {
		child_result_count++;
	}
	child_result_count++;
	auto macro_definition_children_3 = ExtractParseResultsFromList(list_pr.GetChild(3));
	child_result_count += macro_definition_children_3.size();
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	child_slot -= macro_definition_children_3.size();
	for (idx_t child_idx = macro_definition_children_3.size(); child_idx > 0; child_idx--) {
		auto result_idx = child_idx - 1;
		stack.PushFrame(macro_definition_children_3[result_idx].get(), MACRO_DEFINITION_OPS, parent_frame_index,
		                child_slot + result_idx);
	}
	child_slot--;
	stack.PushFrame(list_pr.GetChild(2), QUALIFIED_NAME_OPS, parent_frame_index, child_slot);
	if (if_not_exists_opt_1.HasResult()) {
		child_slot--;
		stack.PushFrame(if_not_exists_opt_1.GetResult(), IF_NOT_EXISTS_OPS, parent_frame_index, child_slot);
	}
	child_slot--;
	stack.PushFrame(list_pr.GetChild(0), MACRO_OR_FUNCTION_OPS, parent_frame_index, child_slot);
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeCreateMacroStmt(PEGTransformer &transformer,
                                                                                TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	auto macro_or_function = frame.TakeResult<bool>(child_slot);
	child_slot++;
	optional<bool> if_not_exists {};
	auto &if_not_exists_opt = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (if_not_exists_opt.HasResult()) {
		auto if_not_exists_value = frame.TakeResult<bool>(child_slot);
		if_not_exists = if_not_exists_value;
		child_slot++;
	}
	auto qualified_name = frame.TakeResult<QualifiedName>(child_slot);
	child_slot++;
	vector<unique_ptr<MacroFunction>> macro_definition;
	auto macro_definition_items = ExtractParseResultsFromList(list_pr.GetChild(3));
	for (idx_t child_idx = 0; child_idx < macro_definition_items.size(); child_idx++) {
		auto &macro_definition_item = macro_definition_items[child_idx];
		auto macro_definition_child_value = frame.TakeResult<unique_ptr<MacroFunction>>(child_slot + child_idx);
		macro_definition.push_back(std::move(macro_definition_child_value));
	}
	child_slot += macro_definition_items.size();
	auto result = TransformCreateMacroStmt(transformer, macro_or_function, if_not_exists, qualified_name,
	                                       std::move(macro_definition));
	return make_uniq<TypedTransformResult<unique_ptr<CreateStatement>>>(std::move(result));
}

