void PEGTransformerFactory::InitializeCreateSecretStmt(PEGTransformer &transformer, TransformStack &stack,
                                                       TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	auto &if_not_exists_opt_0 = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (if_not_exists_opt_0.HasResult()) {
		child_result_count++;
	}
	auto &secret_name_opt_1 = list_pr.GetChild(2).Cast<OptionalParseResult>();
	if (secret_name_opt_1.HasResult()) {
		child_result_count++;
	}
	auto &secret_storage_specifier_opt_2 = list_pr.GetChild(3).Cast<OptionalParseResult>();
	if (secret_storage_specifier_opt_2.HasResult()) {
		child_result_count++;
	}
	child_result_count++;
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	child_slot--;
	stack.PushFrame(list_pr.GetChild(4), GENERIC_COPY_OPTION_LIST_OPS, parent_frame_index, child_slot);
	if (secret_storage_specifier_opt_2.HasResult()) {
		child_slot--;
		stack.PushFrame(secret_storage_specifier_opt_2.GetResult(), SECRET_STORAGE_SPECIFIER_OPS, parent_frame_index,
		                child_slot);
	}
	if (secret_name_opt_1.HasResult()) {
		child_slot--;
		stack.PushFrame(secret_name_opt_1.GetResult(), SECRET_NAME_OPS, parent_frame_index, child_slot);
	}
	if (if_not_exists_opt_0.HasResult()) {
		child_slot--;
		stack.PushFrame(if_not_exists_opt_0.GetResult(), IF_NOT_EXISTS_OPS, parent_frame_index, child_slot);
	}
}

