void PEGTransformerFactory::InitializeCreateSequenceStmt(PEGTransformer &transformer, TransformStack &stack,
                                                         TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	auto &if_not_exists_opt_0 = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (if_not_exists_opt_0.HasResult()) {
		child_result_count++;
	}
	child_result_count++;
	auto &sequence_option_opt_2 = list_pr.GetChild(3).Cast<OptionalParseResult>();
	if (sequence_option_opt_2.HasResult()) {
		auto &sequence_option_repeat_2 = sequence_option_opt_2.GetResult().Cast<RepeatParseResult>();
		child_result_count += sequence_option_repeat_2.GetChildren().size();
	}
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	if (sequence_option_opt_2.HasResult()) {
		auto &sequence_option_repeat_2 = sequence_option_opt_2.GetResult().Cast<RepeatParseResult>();
		auto sequence_option_children_2 = sequence_option_repeat_2.GetChildren();
		child_slot -= sequence_option_children_2.size();
		for (idx_t child_idx = sequence_option_children_2.size(); child_idx > 0; child_idx--) {
			auto result_idx = child_idx - 1;
			stack.PushFrame(sequence_option_children_2[result_idx].get(), SEQUENCE_OPTION_OPS, parent_frame_index,
			                child_slot + result_idx);
		}
	}
	child_slot--;
	stack.PushFrame(list_pr.GetChild(2), QUALIFIED_NAME_OPS, parent_frame_index, child_slot);
	if (if_not_exists_opt_0.HasResult()) {
		child_slot--;
		stack.PushFrame(if_not_exists_opt_0.GetResult(), IF_NOT_EXISTS_OPS, parent_frame_index, child_slot);
	}
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeCreateSequenceStmt(PEGTransformer &transformer,
                                                                                   TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	optional<bool> if_not_exists {};
	auto &if_not_exists_opt = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (if_not_exists_opt.HasResult()) {
		auto if_not_exists_value = frame.TakeResult<bool>(child_slot);
		if_not_exists = if_not_exists_value;
		child_slot++;
	}
	auto qualified_name = frame.TakeResult<QualifiedName>(child_slot);
	child_slot++;
	optional<vector<pair<string, unique_ptr<SequenceOption>>>> sequence_option {};
	auto &sequence_option_opt = list_pr.GetChild(3).Cast<OptionalParseResult>();
	if (sequence_option_opt.HasResult()) {
		vector<pair<string, unique_ptr<SequenceOption>>> sequence_option_value;
		auto &sequence_option_repeat = sequence_option_opt.GetResult().Cast<RepeatParseResult>();
		auto sequence_option_children = sequence_option_repeat.GetChildren();
		for (idx_t child_idx = 0; child_idx < sequence_option_children.size(); child_idx++) {
			sequence_option_value.push_back(
			    frame.TakeResult<pair<string, unique_ptr<SequenceOption>>>(child_slot + child_idx));
		}
		sequence_option = std::move(sequence_option_value);
		child_slot += sequence_option_children.size();
	}
	auto result = TransformCreateSequenceStmt(transformer, if_not_exists, qualified_name, std::move(sequence_option));
	return make_uniq<TypedTransformResult<unique_ptr<CreateStatement>>>(std::move(result));
}

void PEGTransformerFactory::InitializeSequenceOption(PEGTransformer &transformer, TransformStack &stack,
                                                     TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	auto &choice_pr = list_pr.Child<ChoiceParseResult>(0);
	auto &choice_result = choice_pr.GetResult();
	auto &trampoline_ops = GeneratedTrampolineOps();
	auto entry = trampoline_ops.find(choice_result.name);
	if (entry == trampoline_ops.end()) {
		frame.child_results.resize(0);
		return;
	}
	frame.child_results.resize(1);
	stack.PushFrame(choice_result, *entry->second, frame, 0);
}

