void PEGTransformerFactory::InitializeCreateStatement(PEGTransformer &transformer, TransformStack &stack,
                                                      TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	auto &or_replace_opt_0 = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (or_replace_opt_0.HasResult()) {
		child_result_count++;
	}
	auto &temporary_opt_1 = list_pr.GetChild(2).Cast<OptionalParseResult>();
	if (temporary_opt_1.HasResult()) {
		child_result_count++;
	}
	child_result_count++;
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	child_slot--;
	stack.PushFrame(list_pr.GetChild(3), CREATE_STATEMENT_VARIATION_OPS, parent_frame_index, child_slot);
	if (temporary_opt_1.HasResult()) {
		child_slot--;
		stack.PushFrame(temporary_opt_1.GetResult(), TEMPORARY_OPS, parent_frame_index, child_slot);
	}
	if (or_replace_opt_0.HasResult()) {
		child_slot--;
		stack.PushFrame(or_replace_opt_0.GetResult(), OR_REPLACE_OPS, parent_frame_index, child_slot);
	}
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeCreateStatement(PEGTransformer &transformer,
                                                                                TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	optional<bool> or_replace {};
	auto &or_replace_opt = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (or_replace_opt.HasResult()) {
		auto or_replace_value = frame.TakeResult<bool>(child_slot);
		or_replace = or_replace_value;
		child_slot++;
	}
	optional<SecretPersistType> temporary {};
	auto &temporary_opt = list_pr.GetChild(2).Cast<OptionalParseResult>();
	if (temporary_opt.HasResult()) {
		auto temporary_value = frame.TakeResult<SecretPersistType>(child_slot);
		temporary = temporary_value;
		child_slot++;
	}
	auto create_statement_variation = frame.TakeResult<unique_ptr<CreateStatement>>(child_slot);
	child_slot++;
	auto result = TransformCreateStatement(transformer, or_replace, temporary, std::move(create_statement_variation));
	return make_uniq<TypedTransformResult<unique_ptr<SQLStatement>>>(std::move(result));
}

