void PEGTransformerFactory::InitializeDropTable(PEGTransformer &transformer, TransformStack &stack,
                                                TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	child_result_count++;
	auto &if_exists_opt_1 = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (if_exists_opt_1.HasResult()) {
		child_result_count++;
	}
	auto base_table_name_children_2 = ExtractParseResultsFromList(list_pr.GetChild(2));
	child_result_count += base_table_name_children_2.size();
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	child_slot -= base_table_name_children_2.size();
	for (idx_t child_idx = base_table_name_children_2.size(); child_idx > 0; child_idx--) {
		auto result_idx = child_idx - 1;
		stack.PushFrame(base_table_name_children_2[result_idx].get(), BASE_TABLE_NAME_OPS, parent_frame_index,
		                child_slot + result_idx);
	}
	if (if_exists_opt_1.HasResult()) {
		child_slot--;
		stack.PushFrame(if_exists_opt_1.GetResult(), IF_EXISTS_OPS, parent_frame_index, child_slot);
	}
	child_slot--;
	stack.PushFrame(list_pr.GetChild(0), TABLE_OR_VIEW_OPS, parent_frame_index, child_slot);
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeDropTable(PEGTransformer &transformer,
                                                                          TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	auto table_or_view = frame.TakeResult<CatalogType>(child_slot);
	child_slot++;
	optional<bool> if_exists {};
	auto &if_exists_opt = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (if_exists_opt.HasResult()) {
		auto if_exists_value = frame.TakeResult<bool>(child_slot);
		if_exists = if_exists_value;
		child_slot++;
	}
	vector<unique_ptr<BaseTableRef>> base_table_name;
	auto base_table_name_items = ExtractParseResultsFromList(list_pr.GetChild(2));
	for (idx_t child_idx = 0; child_idx < base_table_name_items.size(); child_idx++) {
		auto &base_table_name_item = base_table_name_items[child_idx];
		auto base_table_name_child_value = frame.TakeResult<unique_ptr<BaseTableRef>>(child_slot + child_idx);
		base_table_name.push_back(std::move(base_table_name_child_value));
	}
	child_slot += base_table_name_items.size();
	auto result = TransformDropTable(transformer, table_or_view, if_exists, std::move(base_table_name));
	return make_uniq<TypedTransformResult<unique_ptr<DropStatement>>>(std::move(result));
}

