void PEGTransformerFactory::InitializeExplainOptionList(PEGTransformer &transformer, TransformStack &stack,
                                                        TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	auto explain_option_children_0 = ExtractParseResultsFromList(ExtractResultFromParens(list_pr.GetChild(0)));
	child_result_count += explain_option_children_0.size();
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	child_slot -= explain_option_children_0.size();
	for (idx_t child_idx = explain_option_children_0.size(); child_idx > 0; child_idx--) {
		auto result_idx = child_idx - 1;
		stack.PushFrame(explain_option_children_0[result_idx].get(), EXPLAIN_OPTION_OPS, parent_frame_index,
		                child_slot + result_idx);
	}
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeExplainOptionList(PEGTransformer &transformer,
                                                                                  TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	vector<GenericCopyOption> explain_option;
	auto explain_option_items = ExtractParseResultsFromList(ExtractResultFromParens(list_pr.GetChild(0)));
	for (idx_t child_idx = 0; child_idx < explain_option_items.size(); child_idx++) {
		auto &explain_option_item = explain_option_items[child_idx];
		auto explain_option_child_value = frame.TakeResult<GenericCopyOption>(child_slot + child_idx);
		explain_option.push_back(explain_option_child_value);
	}
	child_slot += explain_option_items.size();
	auto result = TransformExplainOptionList(transformer, explain_option);
	return make_uniq<TypedTransformResult<vector<GenericCopyOption>>>(result);
}

