void PEGTransformerFactory::InitializeFunctionExpression(PEGTransformer &transformer, TransformStack &stack,
                                                         TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	child_result_count++;
	child_result_count++;
	auto &within_group_clause_opt_2 = list_pr.GetChild(2).Cast<OptionalParseResult>();
	if (within_group_clause_opt_2.HasResult()) {
		child_result_count++;
	}
	auto &filter_clause_opt_3 = list_pr.GetChild(3).Cast<OptionalParseResult>();
	if (filter_clause_opt_3.HasResult()) {
		child_result_count++;
	}
	auto &over_clause_opt_4 = list_pr.GetChild(5).Cast<OptionalParseResult>();
	if (over_clause_opt_4.HasResult()) {
		child_result_count++;
	}
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	if (over_clause_opt_4.HasResult()) {
		child_slot--;
		stack.PushFrame(over_clause_opt_4.GetResult(), OVER_CLAUSE_OPS, parent_frame_index, child_slot);
	}
	if (filter_clause_opt_3.HasResult()) {
		child_slot--;
		stack.PushFrame(filter_clause_opt_3.GetResult(), FILTER_CLAUSE_OPS, parent_frame_index, child_slot);
	}
	if (within_group_clause_opt_2.HasResult()) {
		child_slot--;
		stack.PushFrame(within_group_clause_opt_2.GetResult(), WITHIN_GROUP_CLAUSE_OPS, parent_frame_index, child_slot);
	}
	child_slot--;
	stack.PushFrame(list_pr.GetChild(1), FUNCTION_EXPRESSION_ARGUMENTS_OPS, parent_frame_index, child_slot);
	child_slot--;
	stack.PushFrame(list_pr.GetChild(0), FUNCTION_IDENTIFIER_OPS, parent_frame_index, child_slot);
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeFunctionExpression(PEGTransformer &transformer,
                                                                                   TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	auto function_identifier = frame.TakeResult<QualifiedName>(child_slot);
	child_slot++;
	auto function_expression_arguments = frame.TakeResult<MethodArguments>(child_slot);
	child_slot++;
	optional<vector<OrderByNode>> within_group_clause {};
	auto &within_group_clause_opt = list_pr.GetChild(2).Cast<OptionalParseResult>();
	if (within_group_clause_opt.HasResult()) {
		auto within_group_clause_value = frame.TakeResult<vector<OrderByNode>>(child_slot);
		within_group_clause = std::move(within_group_clause_value);
		child_slot++;
	}
	optional<unique_ptr<ParsedExpression>> filter_clause {};
	auto &filter_clause_opt = list_pr.GetChild(3).Cast<OptionalParseResult>();
	if (filter_clause_opt.HasResult()) {
		auto filter_clause_value = frame.TakeResult<unique_ptr<ParsedExpression>>(child_slot);
		filter_clause = std::move(filter_clause_value);
		child_slot++;
	}
	bool has_result {};
	auto &has_result_opt = list_pr.GetChild(4).Cast<OptionalParseResult>();
	has_result = has_result_opt.HasResult();
	optional<unique_ptr<WindowExpression>> over_clause {};
	auto &over_clause_opt = list_pr.GetChild(5).Cast<OptionalParseResult>();
	if (over_clause_opt.HasResult()) {
		auto over_clause_value = frame.TakeResult<unique_ptr<WindowExpression>>(child_slot);
		over_clause = std::move(over_clause_value);
		child_slot++;
	}
	auto result = TransformFunctionExpression(transformer, function_identifier,
	                                          std::move(function_expression_arguments), std::move(within_group_clause),
	                                          std::move(filter_clause), has_result, std::move(over_clause));
	return make_uniq<TypedTransformResult<unique_ptr<ParsedExpression>>>(std::move(result));
}

