void PEGTransformerFactory::InitializeSubqueryExpression(PEGTransformer &transformer, TransformStack &stack,
                                                         TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	auto &subquery_not_opt_0 = list_pr.GetChild(0).Cast<OptionalParseResult>();
	if (subquery_not_opt_0.HasResult()) {
		child_result_count++;
	}
	auto &subquery_exists_opt_1 = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (subquery_exists_opt_1.HasResult()) {
		child_result_count++;
	}
	child_result_count++;
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	child_slot--;
	stack.PushFrame(list_pr.GetChild(2), SUBQUERY_REFERENCE_OPS, parent_frame_index, child_slot);
	if (subquery_exists_opt_1.HasResult()) {
		child_slot--;
		stack.PushFrame(subquery_exists_opt_1.GetResult(), SUBQUERY_EXISTS_OPS, parent_frame_index, child_slot);
	}
	if (subquery_not_opt_0.HasResult()) {
		child_slot--;
		stack.PushFrame(subquery_not_opt_0.GetResult(), SUBQUERY_NOT_OPS, parent_frame_index, child_slot);
	}
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeSubqueryExpression(PEGTransformer &transformer,
                                                                                   TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	optional<bool> subquery_not {};
	auto &subquery_not_opt = list_pr.GetChild(0).Cast<OptionalParseResult>();
	if (subquery_not_opt.HasResult()) {
		auto subquery_not_value = frame.TakeResult<bool>(child_slot);
		subquery_not = subquery_not_value;
		child_slot++;
	}
	optional<bool> subquery_exists {};
	auto &subquery_exists_opt = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (subquery_exists_opt.HasResult()) {
		auto subquery_exists_value = frame.TakeResult<bool>(child_slot);
		subquery_exists = subquery_exists_value;
		child_slot++;
	}
	auto subquery_reference = frame.TakeResult<unique_ptr<TableRef>>(child_slot);
	child_slot++;
	auto result =
	    TransformSubqueryExpression(transformer, subquery_not, subquery_exists, std::move(subquery_reference));
	return make_uniq<TypedTransformResult<unique_ptr<ParsedExpression>>>(std::move(result));
}

