void PEGTransformerFactory::InitializeCaseExpression(PEGTransformer &transformer, TransformStack &stack,
                                                     TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	auto &expression_opt_0 = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (expression_opt_0.HasResult()) {
		child_result_count++;
	}
	auto &case_when_then_repeat_1 = list_pr.GetChild(2).Cast<RepeatParseResult>();
	child_result_count += case_when_then_repeat_1.GetChildren().size();
	auto &case_else_opt_2 = list_pr.GetChild(3).Cast<OptionalParseResult>();
	if (case_else_opt_2.HasResult()) {
		child_result_count++;
	}
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	if (case_else_opt_2.HasResult()) {
		child_slot--;
		stack.PushFrame(case_else_opt_2.GetResult(), CASE_ELSE_OPS, parent_frame_index, child_slot);
	}
	auto case_when_then_children_1 = case_when_then_repeat_1.GetChildren();
	child_slot -= case_when_then_children_1.size();
	for (idx_t child_idx = case_when_then_children_1.size(); child_idx > 0; child_idx--) {
		auto result_idx = child_idx - 1;
		stack.PushFrame(case_when_then_children_1[result_idx].get(), CASE_WHEN_THEN_OPS, parent_frame_index,
		                child_slot + result_idx);
	}
	if (expression_opt_0.HasResult()) {
		child_slot--;
		stack.PushFrame(expression_opt_0.GetResult(), EXPRESSION_OPS, parent_frame_index, child_slot);
	}
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeCaseExpression(PEGTransformer &transformer,
                                                                               TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	optional<unique_ptr<ParsedExpression>> expression {};
	auto &expression_opt = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (expression_opt.HasResult()) {
		auto expression_value = frame.TakeResult<unique_ptr<ParsedExpression>>(child_slot);
		expression = std::move(expression_value);
		child_slot++;
	}
	vector<CaseCheck> case_when_then;
	auto &case_when_then_repeat = list_pr.GetChild(2).Cast<RepeatParseResult>();
	auto case_when_then_children = case_when_then_repeat.GetChildren();
	for (idx_t child_idx = 0; child_idx < case_when_then_children.size(); child_idx++) {
		case_when_then.push_back(frame.TakeResult<CaseCheck>(child_slot + child_idx));
	}
	child_slot += case_when_then_children.size();
	optional<unique_ptr<ParsedExpression>> case_else {};
	auto &case_else_opt = list_pr.GetChild(3).Cast<OptionalParseResult>();
	if (case_else_opt.HasResult()) {
		auto case_else_value = frame.TakeResult<unique_ptr<ParsedExpression>>(child_slot);
		case_else = std::move(case_else_value);
		child_slot++;
	}
	auto result =
	    TransformCaseExpression(transformer, std::move(expression), std::move(case_when_then), std::move(case_else));
	return make_uniq<TypedTransformResult<unique_ptr<ParsedExpression>>>(std::move(result));
}

void PEGTransformerFactory::InitializeCaseWhenThen(PEGTransformer &transformer, TransformStack &stack,
                                                   TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	child_result_count++;
	child_result_count++;
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	child_slot--;
	stack.PushFrame(list_pr.GetChild(3), EXPRESSION_OPS, parent_frame_index, child_slot);
	child_slot--;
	stack.PushFrame(list_pr.GetChild(1), EXPRESSION_OPS, parent_frame_index, child_slot);
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeCaseWhenThen(PEGTransformer &transformer,
                                                                             TransformStackFrame &frame) {
	idx_t child_slot = 0;
	auto expression = frame.TakeResult<unique_ptr<ParsedExpression>>(child_slot);
	child_slot++;
	auto expression_1 = frame.TakeResult<unique_ptr<ParsedExpression>>(child_slot);
	child_slot++;
	auto result = TransformCaseWhenThen(transformer, std::move(expression), std::move(expression_1));
	return make_uniq<TypedTransformResult<CaseCheck>>(std::move(result));
}

