void PEGTransformerFactory::InitializeIntervalParameter(PEGTransformer &transformer, TransformStack &stack,
                                                        TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	auto &choice_pr = list_pr.Child<ChoiceParseResult>(0);
	auto &choice_result = choice_pr.GetResult();
	auto &trampoline_ops = GeneratedTrampolineOps();
	auto entry = trampoline_ops.find(choice_result.name);
	if (entry == trampoline_ops.end()) {
		frame.child_results.resize(0);
		return;
	}
	frame.child_results.resize(1);
	stack.PushFrame(choice_result, *entry->second, frame, 0);
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeIntervalParameter(PEGTransformer &transformer,
                                                                                  TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	auto &choice_pr = list_pr.Child<ChoiceParseResult>(0);
	auto &choice_result = choice_pr.GetResult();
	unique_ptr<ParsedExpression> result;
	if (choice_result.type == ParseResultType::NUMBER) {
		result = TransformNumberLiteral(transformer, choice_result);
	} else {
		result = frame.TakeResult<unique_ptr<ParsedExpression>>(0);
	}
	return make_uniq<TypedTransformResult<unique_ptr<ParsedExpression>>>(std::move(result));
}

