void PEGTransformerFactory::InitializeWindowFrameContents(PEGTransformer &transformer, TransformStack &stack,
                                                          TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	auto &window_partition_opt_0 = list_pr.GetChild(0).Cast<OptionalParseResult>();
	if (window_partition_opt_0.HasResult()) {
		child_result_count++;
	}
	auto &order_by_clause_opt_1 = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (order_by_clause_opt_1.HasResult()) {
		child_result_count++;
	}
	auto &frame_clause_opt_2 = list_pr.GetChild(2).Cast<OptionalParseResult>();
	if (frame_clause_opt_2.HasResult()) {
		child_result_count++;
	}
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	if (frame_clause_opt_2.HasResult()) {
		child_slot--;
		stack.PushFrame(frame_clause_opt_2.GetResult(), FRAME_CLAUSE_OPS, parent_frame_index, child_slot);
	}
	if (order_by_clause_opt_1.HasResult()) {
		child_slot--;
		stack.PushFrame(order_by_clause_opt_1.GetResult(), ORDER_BY_CLAUSE_OPS, parent_frame_index, child_slot);
	}
	if (window_partition_opt_0.HasResult()) {
		child_slot--;
		stack.PushFrame(window_partition_opt_0.GetResult(), WINDOW_PARTITION_OPS, parent_frame_index, child_slot);
	}
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeWindowFrameContents(PEGTransformer &transformer,
                                                                                    TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	optional<vector<unique_ptr<ParsedExpression>>> window_partition {};
	auto &window_partition_opt = list_pr.GetChild(0).Cast<OptionalParseResult>();
	if (window_partition_opt.HasResult()) {
		auto window_partition_value = frame.TakeResult<vector<unique_ptr<ParsedExpression>>>(child_slot);
		window_partition = std::move(window_partition_value);
		child_slot++;
	}
	optional<vector<OrderByNode>> order_by_clause {};
	auto &order_by_clause_opt = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (order_by_clause_opt.HasResult()) {
		auto order_by_clause_value = frame.TakeResult<vector<OrderByNode>>(child_slot);
		order_by_clause = std::move(order_by_clause_value);
		child_slot++;
	}
	optional<WindowFrame> frame_clause {};
	auto &frame_clause_opt = list_pr.GetChild(2).Cast<OptionalParseResult>();
	if (frame_clause_opt.HasResult()) {
		auto frame_clause_value = frame.TakeResult<WindowFrame>(child_slot);
		frame_clause = std::move(frame_clause_value);
		child_slot++;
	}
	auto result = TransformWindowFrameContents(transformer, std::move(window_partition), std::move(order_by_clause),
	                                           std::move(frame_clause));
	return make_uniq<TypedTransformResult<unique_ptr<WindowExpression>>>(std::move(result));
}

