void PEGTransformerFactory::InitializeListComprehensionExpression(PEGTransformer &transformer, TransformStack &stack,
                                                                  TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	child_result_count++;
	auto col_id_or_string_children_1 = ExtractParseResultsFromList(list_pr.GetChild(3));
	child_result_count += col_id_or_string_children_1.size();
	child_result_count++;
	auto &list_comprehension_filter_opt_3 = list_pr.GetChild(6).Cast<OptionalParseResult>();
	if (list_comprehension_filter_opt_3.HasResult()) {
		child_result_count++;
	}
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	if (list_comprehension_filter_opt_3.HasResult()) {
		child_slot--;
		stack.PushFrame(list_comprehension_filter_opt_3.GetResult(), LIST_COMPREHENSION_FILTER_OPS, parent_frame_index,
		                child_slot);
	}
	child_slot--;
	stack.PushFrame(list_pr.GetChild(5), EXPRESSION_OPS, parent_frame_index, child_slot);
	child_slot -= col_id_or_string_children_1.size();
	for (idx_t child_idx = col_id_or_string_children_1.size(); child_idx > 0; child_idx--) {
		auto result_idx = child_idx - 1;
		stack.PushFrame(col_id_or_string_children_1[result_idx].get(), COL_ID_OR_STRING_OPS, parent_frame_index,
		                child_slot + result_idx);
	}
	child_slot--;
	stack.PushFrame(list_pr.GetChild(1), EXPRESSION_OPS, parent_frame_index, child_slot);
}

unique_ptr<TransformResultValue>
PEGTransformerFactory::FinalizeListComprehensionExpression(PEGTransformer &transformer, TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	auto expression = frame.TakeResult<unique_ptr<ParsedExpression>>(child_slot);
	child_slot++;
	vector<Identifier> col_id_or_string;
	auto col_id_or_string_items = ExtractParseResultsFromList(list_pr.GetChild(3));
	for (idx_t child_idx = 0; child_idx < col_id_or_string_items.size(); child_idx++) {
		auto &col_id_or_string_item = col_id_or_string_items[child_idx];
		auto col_id_or_string_child_value = frame.TakeResult<Identifier>(child_slot + child_idx);
		col_id_or_string.push_back(col_id_or_string_child_value);
	}
	child_slot += col_id_or_string_items.size();
	auto expression_1 = frame.TakeResult<unique_ptr<ParsedExpression>>(child_slot);
	child_slot++;
	optional<unique_ptr<ParsedExpression>> list_comprehension_filter {};
	auto &list_comprehension_filter_opt = list_pr.GetChild(6).Cast<OptionalParseResult>();
	if (list_comprehension_filter_opt.HasResult()) {
		auto list_comprehension_filter_value = frame.TakeResult<unique_ptr<ParsedExpression>>(child_slot);
		list_comprehension_filter = std::move(list_comprehension_filter_value);
		child_slot++;
	}
	auto result = TransformListComprehensionExpression(transformer, std::move(expression), col_id_or_string,
	                                                   std::move(expression_1), std::move(list_comprehension_filter));
	return make_uniq<TypedTransformResult<unique_ptr<ParsedExpression>>>(std::move(result));
}

