void PEGTransformerFactory::InitializeIsDistinctFromExpression(PEGTransformer &transformer, TransformStack &stack,
                                                               TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	child_result_count++;
	auto &is_distinct_from_tail_opt_1 = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (is_distinct_from_tail_opt_1.HasResult()) {
		auto &is_distinct_from_tail_repeat_1 = is_distinct_from_tail_opt_1.GetResult().Cast<RepeatParseResult>();
		child_result_count += is_distinct_from_tail_repeat_1.GetChildren().size();
	}
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	if (is_distinct_from_tail_opt_1.HasResult()) {
		auto &is_distinct_from_tail_repeat_1 = is_distinct_from_tail_opt_1.GetResult().Cast<RepeatParseResult>();
		auto is_distinct_from_tail_children_1 = is_distinct_from_tail_repeat_1.GetChildren();
		child_slot -= is_distinct_from_tail_children_1.size();
		for (idx_t child_idx = is_distinct_from_tail_children_1.size(); child_idx > 0; child_idx--) {
			auto result_idx = child_idx - 1;
			stack.PushFrame(is_distinct_from_tail_children_1[result_idx].get(), IS_DISTINCT_FROM_TAIL_OPS,
			                parent_frame_index, child_slot + result_idx);
		}
	}
	child_slot--;
	stack.PushFrame(list_pr.GetChild(0), COMPARISON_EXPRESSION_OPS, parent_frame_index, child_slot);
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeIsDistinctFromExpression(PEGTransformer &transformer,
                                                                                         TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	auto comparison_expression = frame.TakeResult<unique_ptr<ParsedExpression>>(child_slot);
	child_slot++;
	optional<vector<IsDistinctFromTail>> is_distinct_from_tail {};
	auto &is_distinct_from_tail_opt = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (is_distinct_from_tail_opt.HasResult()) {
		vector<IsDistinctFromTail> is_distinct_from_tail_value;
		auto &is_distinct_from_tail_repeat = is_distinct_from_tail_opt.GetResult().Cast<RepeatParseResult>();
		auto is_distinct_from_tail_children = is_distinct_from_tail_repeat.GetChildren();
		for (idx_t child_idx = 0; child_idx < is_distinct_from_tail_children.size(); child_idx++) {
			is_distinct_from_tail_value.push_back(frame.TakeResult<IsDistinctFromTail>(child_slot + child_idx));
		}
		is_distinct_from_tail = std::move(is_distinct_from_tail_value);
		child_slot += is_distinct_from_tail_children.size();
	}
	auto result = TransformIsDistinctFromExpression(transformer, std::move(comparison_expression),
	                                                std::move(is_distinct_from_tail));
	return make_uniq<TypedTransformResult<unique_ptr<ParsedExpression>>>(std::move(result));
}

void PEGTransformerFactory::InitializeIsDistinctFromTail(PEGTransformer &transformer, TransformStack &stack,
                                                         TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	child_result_count++;
	child_result_count++;
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	child_slot--;
	stack.PushFrame(list_pr.GetChild(1), COMPARISON_EXPRESSION_OPS, parent_frame_index, child_slot);
	child_slot--;
	stack.PushFrame(list_pr.GetChild(0), IS_DISTINCT_FROM_OP_OPS, parent_frame_index, child_slot);
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeIsDistinctFromTail(PEGTransformer &transformer,
                                                                                   TransformStackFrame &frame) {
	idx_t child_slot = 0;
	auto is_distinct_from_op = frame.TakeResult<ExpressionType>(child_slot);
	child_slot++;
	auto comparison_expression = frame.TakeResult<unique_ptr<ParsedExpression>>(child_slot);
	child_slot++;
	auto result = TransformIsDistinctFromTail(transformer, is_distinct_from_op, std::move(comparison_expression));
	return make_uniq<TypedTransformResult<IsDistinctFromTail>>(std::move(result));
}

