void PEGTransformerFactory::InitializeComparisonExpression(PEGTransformer &transformer, TransformStack &stack,
                                                           TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	child_result_count++;
	auto &comparison_expression_tail_opt_1 = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (comparison_expression_tail_opt_1.HasResult()) {
		auto &comparison_expression_tail_repeat_1 =
		    comparison_expression_tail_opt_1.GetResult().Cast<RepeatParseResult>();
		child_result_count += comparison_expression_tail_repeat_1.GetChildren().size();
	}
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	if (comparison_expression_tail_opt_1.HasResult()) {
		auto &comparison_expression_tail_repeat_1 =
		    comparison_expression_tail_opt_1.GetResult().Cast<RepeatParseResult>();
		auto comparison_expression_tail_children_1 = comparison_expression_tail_repeat_1.GetChildren();
		child_slot -= comparison_expression_tail_children_1.size();
		for (idx_t child_idx = comparison_expression_tail_children_1.size(); child_idx > 0; child_idx--) {
			auto result_idx = child_idx - 1;
			stack.PushFrame(comparison_expression_tail_children_1[result_idx].get(), COMPARISON_EXPRESSION_TAIL_OPS,
			                parent_frame_index, child_slot + result_idx);
		}
	}
	child_slot--;
	stack.PushFrame(list_pr.GetChild(0), BETWEEN_IN_LIKE_EXPRESSION_OPS, parent_frame_index, child_slot);
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeComparisonExpression(PEGTransformer &transformer,
                                                                                     TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	auto between_in_like_expression = frame.TakeResult<unique_ptr<ParsedExpression>>(child_slot);
	child_slot++;
	optional<vector<ComparisonExpressionTail>> comparison_expression_tail {};
	auto &comparison_expression_tail_opt = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (comparison_expression_tail_opt.HasResult()) {
		vector<ComparisonExpressionTail> comparison_expression_tail_value;
		auto &comparison_expression_tail_repeat = comparison_expression_tail_opt.GetResult().Cast<RepeatParseResult>();
		auto comparison_expression_tail_children = comparison_expression_tail_repeat.GetChildren();
		for (idx_t child_idx = 0; child_idx < comparison_expression_tail_children.size(); child_idx++) {
			comparison_expression_tail_value.push_back(
			    frame.TakeResult<ComparisonExpressionTail>(child_slot + child_idx));
		}
		comparison_expression_tail = std::move(comparison_expression_tail_value);
		child_slot += comparison_expression_tail_children.size();
	}
	auto result = TransformComparisonExpression(transformer, std::move(between_in_like_expression),
	                                            std::move(comparison_expression_tail));
	return make_uniq<TypedTransformResult<unique_ptr<ParsedExpression>>>(std::move(result));
}

void PEGTransformerFactory::InitializeComparisonExpressionTail(PEGTransformer &transformer, TransformStack &stack,
                                                               TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	child_result_count++;
	auto &not_expression_opt_1 = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (not_expression_opt_1.HasResult()) {
		child_result_count++;
	}
	child_result_count++;
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	child_slot--;
	stack.PushFrame(list_pr.GetChild(2), BETWEEN_IN_LIKE_EXPRESSION_OPS, parent_frame_index, child_slot);
	if (not_expression_opt_1.HasResult()) {
		child_slot--;
		stack.PushFrame(not_expression_opt_1.GetResult(), NOT_EXPRESSION_OPS, parent_frame_index, child_slot);
	}
	child_slot--;
	stack.PushFrame(list_pr.GetChild(0), COMPARISON_OPERATOR_OPS, parent_frame_index, child_slot);
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeComparisonExpressionTail(PEGTransformer &transformer,
                                                                                         TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	auto comparison_operator = frame.TakeResult<ExpressionType>(child_slot);
	child_slot++;
	optional<vector<bool>> not_expression {};
	auto &not_expression_opt = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (not_expression_opt.HasResult()) {
		auto not_expression_value = frame.TakeResult<vector<bool>>(child_slot);
		not_expression = std::move(not_expression_value);
		child_slot++;
	}
	auto between_in_like_expression = frame.TakeResult<unique_ptr<ParsedExpression>>(child_slot);
	child_slot++;
	auto result = TransformComparisonExpressionTail(transformer, comparison_operator, std::move(not_expression),
	                                                std::move(between_in_like_expression));
	return make_uniq<TypedTransformResult<ComparisonExpressionTail>>(std::move(result));
}

