void PEGTransformerFactory::InitializeOtherOperatorExpression(PEGTransformer &transformer, TransformStack &stack,
                                                              TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	child_result_count++;
	auto &other_operator_tail_opt_1 = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (other_operator_tail_opt_1.HasResult()) {
		auto &other_operator_tail_repeat_1 = other_operator_tail_opt_1.GetResult().Cast<RepeatParseResult>();
		child_result_count += other_operator_tail_repeat_1.GetChildren().size();
	}
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	if (other_operator_tail_opt_1.HasResult()) {
		auto &other_operator_tail_repeat_1 = other_operator_tail_opt_1.GetResult().Cast<RepeatParseResult>();
		auto other_operator_tail_children_1 = other_operator_tail_repeat_1.GetChildren();
		child_slot -= other_operator_tail_children_1.size();
		for (idx_t child_idx = other_operator_tail_children_1.size(); child_idx > 0; child_idx--) {
			auto result_idx = child_idx - 1;
			stack.PushFrame(other_operator_tail_children_1[result_idx].get(), OTHER_OPERATOR_TAIL_OPS,
			                parent_frame_index, child_slot + result_idx);
		}
	}
	child_slot--;
	stack.PushFrame(list_pr.GetChild(0), BITWISE_EXPRESSION_OPS, parent_frame_index, child_slot);
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeOtherOperatorExpression(PEGTransformer &transformer,
                                                                                        TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	auto bitwise_expression = frame.TakeResult<unique_ptr<ParsedExpression>>(child_slot);
	child_slot++;
	optional<vector<OtherOperatorTail>> other_operator_tail {};
	auto &other_operator_tail_opt = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (other_operator_tail_opt.HasResult()) {
		vector<OtherOperatorTail> other_operator_tail_value;
		auto &other_operator_tail_repeat = other_operator_tail_opt.GetResult().Cast<RepeatParseResult>();
		auto other_operator_tail_children = other_operator_tail_repeat.GetChildren();
		for (idx_t child_idx = 0; child_idx < other_operator_tail_children.size(); child_idx++) {
			other_operator_tail_value.push_back(frame.TakeResult<OtherOperatorTail>(child_slot + child_idx));
		}
		other_operator_tail = std::move(other_operator_tail_value);
		child_slot += other_operator_tail_children.size();
	}
	auto result =
	    TransformOtherOperatorExpression(transformer, std::move(bitwise_expression), std::move(other_operator_tail));
	return make_uniq<TypedTransformResult<unique_ptr<ParsedExpression>>>(std::move(result));
}

