void PEGTransformerFactory::InitializeMergeIntoStatement(PEGTransformer &transformer, TransformStack &stack,
                                                         TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	auto &with_clause_opt_0 = list_pr.GetChild(0).Cast<OptionalParseResult>();
	if (with_clause_opt_0.HasResult()) {
		child_result_count++;
	}
	child_result_count++;
	child_result_count++;
	child_result_count++;
	auto &merge_match_repeat_4 = list_pr.GetChild(6).Cast<RepeatParseResult>();
	child_result_count += merge_match_repeat_4.GetChildren().size();
	auto &returning_clause_opt_5 = list_pr.GetChild(7).Cast<OptionalParseResult>();
	if (returning_clause_opt_5.HasResult()) {
		child_result_count++;
	}
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	if (returning_clause_opt_5.HasResult()) {
		child_slot--;
		stack.PushFrame(returning_clause_opt_5.GetResult(), RETURNING_CLAUSE_OPS, parent_frame_index, child_slot);
	}
	auto merge_match_children_4 = merge_match_repeat_4.GetChildren();
	child_slot -= merge_match_children_4.size();
	for (idx_t child_idx = merge_match_children_4.size(); child_idx > 0; child_idx--) {
		auto result_idx = child_idx - 1;
		stack.PushFrame(merge_match_children_4[result_idx].get(), MERGE_MATCH_OPS, parent_frame_index,
		                child_slot + result_idx);
	}
	child_slot--;
	stack.PushFrame(list_pr.GetChild(5), JOIN_QUALIFIER_OPS, parent_frame_index, child_slot);
	child_slot--;
	stack.PushFrame(list_pr.GetChild(4), MERGE_INTO_USING_CLAUSE_OPS, parent_frame_index, child_slot);
	child_slot--;
	stack.PushFrame(list_pr.GetChild(3), TARGET_OPT_ALIAS_OPS, parent_frame_index, child_slot);
	if (with_clause_opt_0.HasResult()) {
		child_slot--;
		stack.PushFrame(with_clause_opt_0.GetResult(), WITH_CLAUSE_OPS, parent_frame_index, child_slot);
	}
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeMergeIntoStatement(PEGTransformer &transformer,
                                                                                   TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	optional<CommonTableExpressionMap> with_clause {};
	auto &with_clause_opt = list_pr.GetChild(0).Cast<OptionalParseResult>();
	if (with_clause_opt.HasResult()) {
		auto with_clause_value = frame.TakeResult<CommonTableExpressionMap>(child_slot);
		with_clause = std::move(with_clause_value);
		child_slot++;
	}
	auto target_opt_alias = frame.TakeResult<unique_ptr<BaseTableRef>>(child_slot);
	child_slot++;
	auto merge_into_using_clause = frame.TakeResult<unique_ptr<TableRef>>(child_slot);
	child_slot++;
	auto join_qualifier = frame.TakeResult<JoinQualifier>(child_slot);
	child_slot++;
	vector<pair<MergeActionCondition, unique_ptr<MergeIntoAction>>> merge_match;
	auto &merge_match_repeat = list_pr.GetChild(6).Cast<RepeatParseResult>();
	auto merge_match_children = merge_match_repeat.GetChildren();
	for (idx_t child_idx = 0; child_idx < merge_match_children.size(); child_idx++) {
		merge_match.push_back(
		    frame.TakeResult<pair<MergeActionCondition, unique_ptr<MergeIntoAction>>>(child_slot + child_idx));
	}
	child_slot += merge_match_children.size();
	optional<vector<unique_ptr<ParsedExpression>>> returning_clause {};
	auto &returning_clause_opt = list_pr.GetChild(7).Cast<OptionalParseResult>();
	if (returning_clause_opt.HasResult()) {
		auto returning_clause_value = frame.TakeResult<vector<unique_ptr<ParsedExpression>>>(child_slot);
		returning_clause = std::move(returning_clause_value);
		child_slot++;
	}
	auto result = TransformMergeIntoStatement(transformer, std::move(with_clause), std::move(target_opt_alias),
	                                          std::move(merge_into_using_clause), std::move(join_qualifier),
	                                          std::move(merge_match), std::move(returning_clause));
	return make_uniq<TypedTransformResult<unique_ptr<SQLStatement>>>(std::move(result));
}

