void PEGTransformerFactory::InitializeSelectSetOpChain(PEGTransformer &transformer, TransformStack &stack,
                                                       TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	child_result_count++;
	auto &select_set_op_chain_tail_opt_1 = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (select_set_op_chain_tail_opt_1.HasResult()) {
		auto &select_set_op_chain_tail_repeat_1 = select_set_op_chain_tail_opt_1.GetResult().Cast<RepeatParseResult>();
		child_result_count += select_set_op_chain_tail_repeat_1.GetChildren().size();
	}
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	if (select_set_op_chain_tail_opt_1.HasResult()) {
		auto &select_set_op_chain_tail_repeat_1 = select_set_op_chain_tail_opt_1.GetResult().Cast<RepeatParseResult>();
		auto select_set_op_chain_tail_children_1 = select_set_op_chain_tail_repeat_1.GetChildren();
		child_slot -= select_set_op_chain_tail_children_1.size();
		for (idx_t child_idx = select_set_op_chain_tail_children_1.size(); child_idx > 0; child_idx--) {
			auto result_idx = child_idx - 1;
			stack.PushFrame(select_set_op_chain_tail_children_1[result_idx].get(), SELECT_SET_OP_CHAIN_TAIL_OPS,
			                parent_frame_index, child_slot + result_idx);
		}
	}
	child_slot--;
	stack.PushFrame(list_pr.GetChild(0), INTERSECT_CHAIN_OPS, parent_frame_index, child_slot);
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeSelectSetOpChain(PEGTransformer &transformer,
                                                                                 TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	auto intersect_chain = frame.TakeResult<unique_ptr<SelectStatement>>(child_slot);
	child_slot++;
	optional<vector<pair<unique_ptr<SetOperationNode>, unique_ptr<SelectStatement>>>> select_set_op_chain_tail {};
	auto &select_set_op_chain_tail_opt = list_pr.GetChild(1).Cast<OptionalParseResult>();
	if (select_set_op_chain_tail_opt.HasResult()) {
		vector<pair<unique_ptr<SetOperationNode>, unique_ptr<SelectStatement>>> select_set_op_chain_tail_value;
		auto &select_set_op_chain_tail_repeat = select_set_op_chain_tail_opt.GetResult().Cast<RepeatParseResult>();
		auto select_set_op_chain_tail_children = select_set_op_chain_tail_repeat.GetChildren();
		for (idx_t child_idx = 0; child_idx < select_set_op_chain_tail_children.size(); child_idx++) {
			select_set_op_chain_tail_value.push_back(
			    frame.TakeResult<pair<unique_ptr<SetOperationNode>, unique_ptr<SelectStatement>>>(child_slot +
			                                                                                      child_idx));
		}
		select_set_op_chain_tail = std::move(select_set_op_chain_tail_value);
		child_slot += select_set_op_chain_tail_children.size();
	}
	auto result =
	    TransformSelectSetOpChain(transformer, std::move(intersect_chain), std::move(select_set_op_chain_tail));
	return make_uniq<TypedTransformResult<unique_ptr<SelectStatement>>>(std::move(result));
}

