unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeTablePivotClauseBody(PEGTransformer &transformer,
                                                                                     TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	auto target_list = frame.TakeResult<vector<unique_ptr<ParsedExpression>>>(child_slot);
	child_slot++;
	vector<PivotColumn> pivot_value_list;
	auto &pivot_value_list_repeat = list_pr.GetChild(2).Cast<RepeatParseResult>();
	auto pivot_value_list_children = pivot_value_list_repeat.GetChildren();
	for (idx_t child_idx = 0; child_idx < pivot_value_list_children.size(); child_idx++) {
		pivot_value_list.push_back(frame.TakeResult<PivotColumn>(child_slot + child_idx));
	}
	child_slot += pivot_value_list_children.size();
	optional<vector<string>> pivot_group_by_list {};
	auto &pivot_group_by_list_opt = list_pr.GetChild(3).Cast<OptionalParseResult>();
	if (pivot_group_by_list_opt.HasResult()) {
		auto pivot_group_by_list_value = frame.TakeResult<vector<string>>(child_slot);
		pivot_group_by_list = pivot_group_by_list_value;
		child_slot++;
	}
	auto result = TransformTablePivotClauseBody(transformer, std::move(target_list), std::move(pivot_value_list),
	                                            pivot_group_by_list);
	return make_uniq<TypedTransformResult<unique_ptr<TableRef>>>(std::move(result));
}

