void PEGTransformerFactory::InitializeFromClause(PEGTransformer &transformer, TransformStack &stack,
                                                 TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	auto table_ref_children_0 = ExtractParseResultsFromList(list_pr.GetChild(1));
	child_result_count += table_ref_children_0.size();
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	child_slot -= table_ref_children_0.size();
	for (idx_t child_idx = table_ref_children_0.size(); child_idx > 0; child_idx--) {
		auto result_idx = child_idx - 1;
		stack.PushFrame(table_ref_children_0[result_idx].get(), TABLE_REF_OPS, parent_frame_index,
		                child_slot + result_idx);
	}
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeFromClause(PEGTransformer &transformer,
                                                                           TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	vector<unique_ptr<TableRef>> table_ref;
	auto table_ref_items = ExtractParseResultsFromList(list_pr.GetChild(1));
	for (idx_t child_idx = 0; child_idx < table_ref_items.size(); child_idx++) {
		auto &table_ref_item = table_ref_items[child_idx];
		auto table_ref_child_value = frame.TakeResult<unique_ptr<TableRef>>(child_slot + child_idx);
		table_ref.push_back(std::move(table_ref_child_value));
	}
	child_slot += table_ref_items.size();
	auto result = TransformFromClause(transformer, std::move(table_ref));
	return make_uniq<TypedTransformResult<unique_ptr<TableRef>>>(std::move(result));
}

