void PEGTransformerFactory::InitializeValuesClause(PEGTransformer &transformer, TransformStack &stack,
                                                   TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	auto values_expressions_children_0 = ExtractParseResultsFromList(list_pr.GetChild(1));
	child_result_count += values_expressions_children_0.size();
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	child_slot -= values_expressions_children_0.size();
	for (idx_t child_idx = values_expressions_children_0.size(); child_idx > 0; child_idx--) {
		auto result_idx = child_idx - 1;
		stack.PushFrame(values_expressions_children_0[result_idx].get(), VALUES_EXPRESSIONS_OPS, parent_frame_index,
		                child_slot + result_idx);
	}
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeValuesClause(PEGTransformer &transformer,
                                                                             TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	vector<vector<unique_ptr<ParsedExpression>>> values_expressions;
	auto values_expressions_items = ExtractParseResultsFromList(list_pr.GetChild(1));
	for (idx_t child_idx = 0; child_idx < values_expressions_items.size(); child_idx++) {
		auto &values_expressions_item = values_expressions_items[child_idx];
		auto values_expressions_child_value =
		    frame.TakeResult<vector<unique_ptr<ParsedExpression>>>(child_slot + child_idx);
		values_expressions.push_back(std::move(values_expressions_child_value));
	}
	child_slot += values_expressions_items.size();
	auto result = TransformValuesClause(transformer, std::move(values_expressions));
	return make_uniq<TypedTransformResult<unique_ptr<SelectStatement>>>(std::move(result));
}

void PEGTransformerFactory::InitializeValuesExpressions(PEGTransformer &transformer, TransformStack &stack,
                                                        TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	auto expression_children_0 = ExtractParseResultsFromList(ExtractResultFromParens(list_pr.GetChild(0)));
	child_result_count += expression_children_0.size();
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	child_slot -= expression_children_0.size();
	for (idx_t child_idx = expression_children_0.size(); child_idx > 0; child_idx--) {
		auto result_idx = child_idx - 1;
		stack.PushFrame(expression_children_0[result_idx].get(), EXPRESSION_OPS, parent_frame_index,
		                child_slot + result_idx);
	}
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeValuesExpressions(PEGTransformer &transformer,
                                                                                  TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	vector<unique_ptr<ParsedExpression>> expression;
	auto expression_items = ExtractParseResultsFromList(ExtractResultFromParens(list_pr.GetChild(0)));
	for (idx_t child_idx = 0; child_idx < expression_items.size(); child_idx++) {
		auto &expression_item = expression_items[child_idx];
		auto expression_child_value = frame.TakeResult<unique_ptr<ParsedExpression>>(child_slot + child_idx);
		expression.push_back(std::move(expression_child_value));
	}
	child_slot += expression_items.size();
	auto result = TransformValuesExpressions(transformer, std::move(expression));
	return make_uniq<TypedTransformResult<vector<unique_ptr<ParsedExpression>>>>(std::move(result));
}

