void PEGTransformerFactory::InitializeUpdateStatement(PEGTransformer &transformer, TransformStack &stack,
                                                      TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_result_count = 0;
	auto &with_clause_opt_0 = list_pr.GetChild(0).Cast<OptionalParseResult>();
	if (with_clause_opt_0.HasResult()) {
		child_result_count++;
	}
	child_result_count++;
	child_result_count++;
	auto &from_clause_opt_3 = list_pr.GetChild(4).Cast<OptionalParseResult>();
	if (from_clause_opt_3.HasResult()) {
		child_result_count++;
	}
	auto &where_clause_opt_4 = list_pr.GetChild(5).Cast<OptionalParseResult>();
	if (where_clause_opt_4.HasResult()) {
		child_result_count++;
	}
	auto &returning_clause_opt_5 = list_pr.GetChild(6).Cast<OptionalParseResult>();
	if (returning_clause_opt_5.HasResult()) {
		child_result_count++;
	}
	frame.child_results.resize(child_result_count);
	auto parent_frame_index = frame.frame_index;
	idx_t child_slot = child_result_count;
	if (returning_clause_opt_5.HasResult()) {
		child_slot--;
		stack.PushFrame(returning_clause_opt_5.GetResult(), RETURNING_CLAUSE_OPS, parent_frame_index, child_slot);
	}
	if (where_clause_opt_4.HasResult()) {
		child_slot--;
		stack.PushFrame(where_clause_opt_4.GetResult(), WHERE_CLAUSE_OPS, parent_frame_index, child_slot);
	}
	if (from_clause_opt_3.HasResult()) {
		child_slot--;
		stack.PushFrame(from_clause_opt_3.GetResult(), FROM_CLAUSE_OPS, parent_frame_index, child_slot);
	}
	child_slot--;
	stack.PushFrame(list_pr.GetChild(3), UPDATE_SET_CLAUSE_OPS, parent_frame_index, child_slot);
	child_slot--;
	stack.PushFrame(list_pr.GetChild(2), UPDATE_TARGET_OPS, parent_frame_index, child_slot);
	if (with_clause_opt_0.HasResult()) {
		child_slot--;
		stack.PushFrame(with_clause_opt_0.GetResult(), WITH_CLAUSE_OPS, parent_frame_index, child_slot);
	}
}

unique_ptr<TransformResultValue> PEGTransformerFactory::FinalizeUpdateStatement(PEGTransformer &transformer,
                                                                                TransformStackFrame &frame) {
	auto &list_pr = frame.parse_result.Cast<ListParseResult>();
	idx_t child_slot = 0;
	optional<CommonTableExpressionMap> with_clause {};
	auto &with_clause_opt = list_pr.GetChild(0).Cast<OptionalParseResult>();
	if (with_clause_opt.HasResult()) {
		auto with_clause_value = frame.TakeResult<CommonTableExpressionMap>(child_slot);
		with_clause = std::move(with_clause_value);
		child_slot++;
	}
	auto update_target = frame.TakeResult<unique_ptr<TableRef>>(child_slot);
	child_slot++;
	auto update_set_clause = frame.TakeResult<unique_ptr<UpdateSetInfo>>(child_slot);
	child_slot++;
	optional<unique_ptr<TableRef>> from_clause {};
	auto &from_clause_opt = list_pr.GetChild(4).Cast<OptionalParseResult>();
	if (from_clause_opt.HasResult()) {
		auto from_clause_value = frame.TakeResult<unique_ptr<TableRef>>(child_slot);
		from_clause = std::move(from_clause_value);
		child_slot++;
	}
	optional<unique_ptr<ParsedExpression>> where_clause {};
	auto &where_clause_opt = list_pr.GetChild(5).Cast<OptionalParseResult>();
	if (where_clause_opt.HasResult()) {
		auto where_clause_value = frame.TakeResult<unique_ptr<ParsedExpression>>(child_slot);
		where_clause = std::move(where_clause_value);
		child_slot++;
	}
	optional<vector<unique_ptr<ParsedExpression>>> returning_clause {};
	auto &returning_clause_opt = list_pr.GetChild(6).Cast<OptionalParseResult>();
	if (returning_clause_opt.HasResult()) {
		auto returning_clause_value = frame.TakeResult<vector<unique_ptr<ParsedExpression>>>(child_slot);
		returning_clause = std::move(returning_clause_value);
		child_slot++;
	}
	auto result = TransformUpdateStatement(transformer, std::move(with_clause), std::move(update_target),
	                                       std::move(update_set_clause), std::move(from_clause),
	                                       std::move(where_clause), std::move(returning_clause));
	return make_uniq<TypedTransformResult<unique_ptr<SQLStatement>>>(std::move(result));
}

